import{_ as r,o as t,c as e,a2 as o}from"./chunks/framework.VxKNwi4m.js";const c=JSON.parse('{"title":"운영비 내역 관리","description":"","frontmatter":{},"headers":[],"relativePath":"ledger/imprest.md","filePath":"ledger/imprest.md","lastUpdated":1783223740000}'),l={name:"ledger/imprest.md"};function i(n,a,s,h,d,g){return t(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="운영비-내역-관리" tabindex="-1">운영비 내역 관리 <a class="header-anchor" href="#운영비-내역-관리" aria-label="Permalink to &quot;운영비 내역 관리&quot;">​</a></h1><p>프로젝트 수행을 위해 별도로 운영되는 운영비(전도금) 계좌의 입출금 내역을 기록하고, 이를 회계 계정 및 프로젝트별 계약 정보와 연결하여 관리하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>회계 자금 관리 &gt; 운영비 내역 관리</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>본사 관리 계좌 외에 프로젝트 현장에서 사용하는 운영비 계좌(이하 운영 계좌)의 실제 거래 데이터를 등록합니다. 등록된 거래는 회계상 적절한 계정 과목으로 분류되어야 하며, 특히 외주비나 사업비 집행 시 관련 계약 정보와 매칭하여 프로젝트 비용 집행의 투명성을 확보합니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li><strong>운영비 특화 필터링</strong>: 프로젝트별 운영 계좌(Imprest Account)를 기준으로 기간별, 계정별 내역 조회</li><li><strong>다수 거래 일괄 등록</strong>: 신규 등록 시 여러 건의 독립된 은행 거래를 한 화면에서 동시에 입력 가능</li><li><strong>인라인 편집 (Inline Editing)</strong>: 목록 화면에서 항목을 더블 클릭하여 적요, 메모, 금액, 계정 등을 즉시 수정</li><li><strong>이체 수수료 자동 입력</strong>: 출금 항목 옆의 아이콘 클릭 시 이체 수수료(500원) 분개를 자동으로 생성</li><li><strong>대체 거래 자동 감지</strong>: 대체(출금) 계정 선택 시 상대 계좌의 대체(입금) 거래건을 자동으로 추가 제안</li><li><strong>엑셀 연동 및 템플릿</strong>: 회계 분류 내역의 엑셀 템플릿 다운로드 및 대량 업로드 지원</li><li><strong>하이라이트 이동</strong>: 외부 메뉴(예: 자금 일보)에서 유입 시 해당 거래를 즉시 찾아 스크롤 및 강조 표시</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-목록-제어-및-필터링" tabindex="-1">1. 목록 제어 및 필터링 <a class="header-anchor" href="#_1-목록-제어-및-필터링" aria-label="Permalink to &quot;1. 목록 제어 및 필터링&quot;">​</a></h3><p>특정 프로젝트의 운영비 내역을 조건별로 검색하는 영역입니다.</p><ul><li><strong>검색 조건</strong>: 거래일자 범위, 입출금 구분, 계정 분류, 운영 계좌 선택, 관련 계약 정보 및 검색어(적요/거래처)</li><li><strong>조회 결과</strong>: 하단에 조건에 부합하는 전체 거래 건수가 표시되어 데이터 규모를 즉시 확인 가능합니다.</li></ul><h3 id="_2-운영비-입출금-목록" tabindex="-1">2. 운영비 입출금 목록 <a class="header-anchor" href="#_2-운영비-입출금-목록" aria-label="Permalink to &quot;2. 운영비 입출금 목록&quot;">​</a></h3><p>조회된 내역을 테이블 형태로 표시하며, 각 행은 &#39;은행거래내역&#39;과 &#39;분류 내역&#39;으로 구성됩니다.</p><ul><li><strong>은행거래내역</strong>: 실제 통장에 기록된 날짜, 계좌 별칭, 적요, 입/출금액 및 확인 상태 표시</li><li><strong>분류 내역 (분개)</strong>: 해당 거래의 회계 계정, 거래처, 분류 금액, 지출 증빙 정보. 계약 정보가 연결된 경우 아이콘(📖, 👤)으로 표시됩니다.</li><li><strong>금액 일치 검증</strong>: 거래 금액과 분류 금액의 합계가 일치하면 ✅ 아이콘이 표시됩니다. 불일치 시 차액 정보가 노란색 경고 행으로 표시됩니다.</li></ul><h3 id="_3-거래-등록-및-수정" tabindex="-1">3. 거래 등록 및 수정 <a class="header-anchor" href="#_3-거래-등록-및-수정" aria-label="Permalink to &quot;3. 거래 등록 및 수정&quot;">​</a></h3><p>새로운 내역을 생성하거나 기존 내역을 수정하는 화면입니다.</p><ul><li><strong>신규 등록 (다수 건)</strong>: [새 거래 등록] 버튼을 통해 여러 건의 은행 거래를 동시에 추가할 수 있는 행 기반 입력 폼을 제공합니다.</li><li><strong>상세 수정</strong>: 개별 행의 수정 아이콘을 클릭하여 상세 수정 페이지로 진입하거나, 목록에서 더블 클릭하여 필요한 필드만 인라인으로 수정할 수 있습니다.</li></ul><h2 id="💡-주요-관리-포인트" tabindex="-1">💡 주요 관리 포인트 <a class="header-anchor" href="#💡-주요-관리-포인트" aria-label="Permalink to &quot;💡 주요 관리 포인트&quot;">​</a></h2><h3 id="인라인-편집과-데이터-반영" tabindex="-1">인라인 편집과 데이터 반영 <a class="header-anchor" href="#인라인-편집과-데이터-반영" aria-label="Permalink to &quot;인라인 편집과 데이터 반영&quot;">​</a></h3><p>목록에서 더블 클릭을 통해 즉시 수정할 수 있습니다. 특히 <strong>계정 과목</strong> 수정 시, 해당 계정이 계약 정보나 계약자 매칭이 필수인 경우 자동으로 선택 팝업이 호출되어 데이터의 정합성을 강제합니다.</p><h3 id="과거-데이터-수정-제한" tabindex="-1">과거 데이터 수정 제한 <a class="header-anchor" href="#과거-데이터-수정-제한" aria-label="Permalink to &quot;과거 데이터 수정 제한&quot;">​</a></h3><p>데이터 무결성 보호를 위해 <strong>최종 정산 일자</strong> 이전의 데이터나, 등록 후 일정 기간(기본 10일)이 경과한 과거 데이터는 일반 권한으로 수정이 제한됩니다. 수정이 필요한 경우 상급 권한(SuperAuth)을 가진 관리자에게 요청해야 합니다.</p><h3 id="대체-거래-자금-이체-처리" tabindex="-1">대체 거래(자금 이체) 처리 <a class="header-anchor" href="#대체-거래-자금-이체-처리" aria-label="Permalink to &quot;대체 거래(자금 이체) 처리&quot;">​</a></h3><p>운영 계좌 간 자금 이동이나 본사 계좌에서 운영 계좌로 자금을 넘겨받는 경우, 출금 측에서 &#39;대체(출금)&#39; 계정을 선택하면 시스템이 입금 측의 &#39;대체(입금)&#39; 거래를 자동으로 생성할지 확인합니다. 이를 통해 이중 입력의 번거로움을 줄이고 자금 흐름을 일치시킵니다.</p>',24)])])}const p=r(l,[["render",i]]);export{c as __pageData,p as default};
